import React from "react";
import securityImg from "../../assets/security 2.png";
import uptimeImg from "../../assets/uptime.png";
import uptimeImg from "../../assets/uptime.png";
import complianceImg from "../../assets/compliance.png";
import ScrollReveal from "../ui/ScrollReveal";
import StaggerContainer from "../ui/StaggerContainer";
import StaggerItem from "../ui/StaggerItem";

const features = [
  {
    title: "High-Level Data Security",
    description:
      "End-to-end encryption, regular audits, and automated backups keep your employee data secure.",
    image: securityImg,
    gradient:
      "radial-gradient(100% 100% at 50% 0%, rgba(3, 169, 244, 0.15) 0%, rgba(255, 255, 255, 0.15) 75%)",
  },
  {
    title: "99.9% Uptime Guarantee",
    description:
      "Enterprise-grade infrastructure ensures your HRMS is always available when you need it.",
    image: uptimeImg,
    gradient:
      "radial-gradient(100% 100% at 50% 0%, rgba(255, 215, 0, 0.15) 0%, rgba(255, 255, 255, 0.15) 75%)",
  },
  {
    title: "Compliance Ready",
    description:
      "Built to meet Indian labor laws, GDPR standards, and industry compliance requirements out of the box.",
    image: complianceImg,
    gradient:
      "radial-gradient(100% 100% at 50% 0%, rgba(53, 183, 41, 0.15) 0%, rgba(255, 255, 255, 0.15) 75%)",
  },
];

const DeliveryReliabilitySection = () => {
  return (
    <section className="w-full bg-white py-[60px] sm:py-[80px] md:py-[100px]">
      <div className="w-full max-w-[1240px] mx-auto px-4 sm:px-6 md:px-8">
        {/* Header Section */}
        <ScrollReveal className="flex flex-col items-center">
          <h2 className="font-['Bricolage_Grotesque'] font-semibold text-[24px] sm:text-[28px] text-[#212125] text-center leading-[120%]">
            Enterprise-Grade{" "}
            <span className="text-[#35B729]">Delivery & Reliability</span>
          </h2>
          <p className="font-inter text-[10px] sm:text-[14px] text-[#75757A] text-center mt-2 max-w-[600px]">
            Built for teams that care about data security, compliance, and
            customer success
          </p>
        </ScrollReveal>

        <StaggerContainer className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4 sm:gap-6 lg:gap-8 mt-[30px] sm:mt-[50px] justify-items-center w-full max-w-[320px] sm:max-w-none mx-auto">
          {features.map((feature, index) => (
            <StaggerItem
              key={index}
              style={{ background: feature.gradient }}
              className="w-full lg:w-[380px] h-full lg:h-[415px] rounded-[24px] sm:rounded-[30px] pt-[20px] sm:pt-[40px] pb-[20px] sm:pb-[40px] px-[14px] sm:px-[30px] border border-[#E9EDEF] flex flex-col items-center"
            >
              {/* Card Image */}
              <div className="mb-2 sm:mb-4">
                <img
                  src={feature.image}
                  alt={feature.title}
                  className="w-full max-w-[120px] sm:max-w-[180px] lg:max-w-[266.67px] h-auto object-contain mx-auto"
                />
              </div>

              {/* Card Content */}
              <div className="text-center mt-auto">
                <h3 className="font-['Bricolage_Grotesque'] font-bold text-[18px] sm:text-[22px] lg:text-[24px] text-[#212125] text-center leading-[120%]">
                  {feature.title}
                </h3>
                <p className="font-inter font-normal text-[11px] sm:text-[15px] lg:text-[18px] text-[#75757A] text-center leading-[120%] mt-1 sm:mt-2">
                  {feature.description}
                </p>
              </div>
            </StaggerItem>
          ))}
        </StaggerContainer>
      </div>
    </section>
  );
};

export default DeliveryReliabilitySection;

import { useEffect, useState } from "react";
import { motion } from "framer-motion";
import ScrollReveal from "../ui/ScrollReveal";
import setupIcon from "../../assets/setup.png";
import importIcon from "../../assets/import.png";
import trainingIcon from "../../assets/training.png";
import onboardingIcon from "../../assets/onboarding.png";
import supportIcon from "../../assets/support2.png";
import img1 from "../../assets/imp.png";
import img2 from "../../assets/emp.png";
import img3 from "../../assets/team.png";
import img4 from "../../assets/onbo.png";
import img5 from "../../assets/247.png";

const steps = [
  {
    icon: setupIcon,
    title: "Setup & Configuration",
    description:
      "Install HRMS, configure company settings, set work timings (10 AM - 7 PM, etc.), and define leave policy",
    image: img1,
    color: "#22C55E",
  },
  {
    icon: importIcon,
    title: "Employee Data Import",
    description:
      "Import employee master data (role, department, designation), set up team structure, and assign team leads",
    image: img2,
    color: "#EC4899",
  },
  {
    icon: trainingIcon,
    title: "Team Training",
    description:
      "Train the HR team on leave approvals, analytics dashboard, and reporting. Train team leads on attendance visibility",
    image: img3,
    color: "#6366F1",
  },
  {
    icon: onboardingIcon,
    title: "Employee Onboarding",
    description:
      "Show employees self-service portal, clock-in/out process, leave submission, document upload",
    image: img4,
    color: "#F59E0B",
  },
  {
    icon: supportIcon,
    title: "Support Included",
    description:
      "24/7 email support, implementation assistance, and monthly optimization check-ins for continuous success.",
    image: img5,
    color: "#0EA5E9",
  },
];

export default function ImplementationSupportSection() {
  const [activeIndex, setActiveIndex] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setActiveIndex((prev) => (prev + 1) % steps.length);
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  return (
    <section className="w-full bg-white py-[60px] sm:py-[80px] md:py-[120px] xl:py-[120px]">
      <div className="w-full max-w-[1240px] mx-auto px-4 sm:px-6 md:px-8">
        <div className="bg-[#FAFBFC] rounded-[30px] lg:rounded-[50px] p-6 sm:p-8 md:p-[60px] lg:p-[70px]">
          {/* Section Header */}
          <ScrollReveal>
            <div className="flex flex-col items-center text-center mb-[56px] sm:mb-[50px] md:mb-[60px] lg:mb-[70px]">
              <h2 className="font-['Bricolage_Grotesque'] font-bold text-[28px] sm:text-[32px] md:text-[36px] lg:text-[42px] leading-[120%] text-[#212125]">
                <span className="text-[#35B729]">Implementation</span> & Support
              </h2>
              <p className="mt-2 font-inter font-normal text-[12px] sm:text-[14px] text-[#75757A]">
                We make your transition smooth and hassle-free
              </p>
            </div>
          </ScrollReveal>

          {/* Content Layout */}
          <div className="flex flex-col lg:flex-row gap-[36px] sm:gap-[50px] lg:gap-[80px] xl:gap-[120px] items-center lg:items-start justify-between">
            {/* Left Side: Illustration */}
            <div className="flex-1 w-full flex justify-center lg:justify-start">
              <div className="overflow-hidden w-full max-w-[330px] sm:max-w-[380px] lg:max-w-[500px]">
                <div
                  className="flex transition-transform duration-500"
                  style={{ transform: `translateX(-${activeIndex * 100}%)` }}
                >
                  {steps.map((step, index) => (
                    <div key={index} className="min-w-full flex justify-center">
                      <img
                        src={step.image}
                        alt={`${step.title} illustration`}
                        className="w-full max-w-none object-contain transition-all duration-500 ease-in-out"
                      />
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Right Side: Timeline */}
            <div className="flex-1 w-full max-w-[560px] relative">
              {/* Background Vertical Line */}
              <div className="absolute left-[22px] md:left-[26px] top-0 bottom-0 w-[2px] bg-gray-200" />

              {/* Active Progress Line */}
              <motion.div
                className="absolute left-[22px] md:left-[26px] top-0 w-[2px]"
                animate={{
                  height: `${(activeIndex + 1) * 80}px`,
                  backgroundColor: steps[activeIndex].color,
                }}
                transition={{ duration: 0.5, ease: "easeInOut" }}
              />

              {/* Steps */}
              <div className="flex flex-col gap-[30px] md:gap-[40px] lg:gap-[45px]">
                {steps.map((step, index) => (
                  <div
                    key={index}
                    className="flex items-start gap-[16px] relative z-20 cursor-pointer"
                    onClick={() => setActiveIndex(index)}
                  >
                    {(() => {
                      const isActive = activeIndex === index;
                      const activeColor = step.color;

                      return (
                        <>
                          {/* Icon Circle */}
                          <motion.div
                            className="flex-shrink-0 w-[44px] h-[44px] md:w-[52px] md:h-[52px] rounded-full flex items-center justify-center border-4 border-white shadow-sm"
                            animate={{
                              backgroundColor: isActive ? activeColor : "#F3F4F6",
                              boxShadow: isActive ? `0 0 0 6px ${activeColor}20` : "none",
                              scale: isActive ? 1.1 : 1,
                            }}
                            transition={{ duration: 0.5, ease: "easeInOut" }}
                          >
                            <img
                              src={step.icon}
                              alt=""
                              className={`w-[24px] h-[24px] md:w-[28px] md:h-[28px] object-contain ${
                                isActive ? "brightness-0 invert" : ""
                              }`}
                            />
                          </motion.div>

                          {/* Text Content */}
                          <div className="flex flex-col">
                            <h3
                              className={`font-['Bricolage_Grotesque'] text-[18px] transition-colors duration-300 ${
                                isActive
                                  ? "font-semibold text-[#212125]"
                                  : "font-medium text-[#6B7280]"
                              }`}
                            >
                              {step.title}
                            </h3>
                            <p className="mt-[4px] font-inter font-normal text-[14px] leading-[140%] text-[#75757A]">
                              {step.description}
                            </p>
                          </div>
                        </>
                      );
                    })()}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

import React from "react";
import resource1 from "../../assets/resource1.png";
import resource2 from "../../assets/resource2.png";
import resource2 from "../../assets/resource2.png";
import resource3 from "../../assets/resource3.png";
import ScrollReveal from "../ui/ScrollReveal";
import StaggerContainer from "../ui/StaggerContainer";
import StaggerItem from "../ui/StaggerItem";

const resources = [
  {
