export default ResourcesSection;

import { motion } from "framer-motion";

export default function Button({ children, variant = 'primary', className = '', ...props }) {
  const baseStyles = "inline-flex items-center justify-center px-6 py-2.5 rounded-xl font-medium transition-colors text-sm";
  
  const variants = {
    primary: "bg-[#35B729] text-white hover:bg-[#2da422]",
    outline: "border border-[#35B729] bg-transparent text-[#35B729] hover:bg-[#35B729]/5",
    ghost: "bg-transparent text-slate-600 hover:text-[#35B729] hover:bg-slate-50"
  };

  return (
    <motion.button 
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      transition={{ duration: 0.2 }}
      className={`${baseStyles} ${variants[variant]} ${className}`} 
      {...props}
    >
      {children}
    </motion.button>
  );
}

import { motion } from "framer-motion";

export default function ScrollReveal({ children, className = "", delay = 0, ...props }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 40 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true, margin: "-50px" }}
      transition={{ duration: 0.6, ease: "easeOut", delay }}
      className={className}
      {...props}
    >
      {children}
    </motion.div>
  );
}

import { motion } from "framer-motion";

export default function StaggerContainer({ children, className = "", delayChildren = 0.1, staggerChildren = 0.15 }) {
  return (
    <motion.div
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true, margin: "-50px" }}
      variants={{
        hidden: {},
        visible: {
          transition: {
            delayChildren,
            staggerChildren,
          },
        },
      }}
      className={className}
    >
      {children}
    </motion.div>
  );
}

import { motion } from "framer-motion";

export default function StaggerItem({ children, className = "" }) {
  return (
    <motion.div
      variants={{
        hidden: { opacity: 0, y: 40 },
        visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: "easeOut" } },
      }}
      className={className}
    >
      {children}
    </motion.div>
  );
}
